import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const Login = () => {
  const navigate = useNavigate();

  const [form, setForm] = useState({
    email: '',
    password: ''
  });

  // handle input
  const handleChange = (e) => {
    setForm({
      ...form,
      [e.target.name]: e.target.value
    });
  };

  // submit
  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      const res = await axios.post(
        'http://localhost:5001/api/auth/login',
        {
          email: form.email,
          password: form.password
        }
      );

      // 🔥 IMPORTANT (SAVE USER DATA)
      localStorage.setItem("userId", res.data.userId);
      localStorage.setItem("userName", res.data.name);

      alert('Login Successful ✅');

      navigate('/dashboard'); // 👉 better than "/"

    } catch (err) {
      alert(err.response?.data || 'Error ❌');
      console.log(err);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[rgb(35,46,88)]">

      <div className="backdrop-blur-lg bg-white/10 border border-white/20 shadow-xl rounded-2xl p-8 w-full max-w-md text-white">

        <h2 className="text-3xl font-bold text-center mb-6">Login</h2>

        <form className="space-y-5" onSubmit={handleSubmit}>

          {/* Email */}
          <div>
            <label className="block mb-1 text-sm">Email</label>
            <input
              type="email"
              name="email"
              placeholder="Enter your email"
              value={form.email}
              onChange={handleChange}
              required
              className="w-full px-4 py-2 rounded-lg bg-white/20 border border-white/30 placeholder-white/70 focus:outline-none focus:ring-2 focus:ring-white"
            />
          </div>

          {/* Password */}
          <div>
            <label className="block mb-1 text-sm">Password</label>
            <input
              type="password"
              name="password"
              placeholder="Enter password"
              value={form.password}
              onChange={handleChange}
              required
              className="w-full px-4 py-2 rounded-lg bg-white/20 border border-white/30 placeholder-white/70 focus:outline-none focus:ring-2 focus:ring-white"
            />
          </div>

          {/* Button */}
          <button
            type="submit"
            className="w-full py-2 rounded-lg bg-white text-[rgb(35,46,88)] font-semibold hover:bg-white/90 transition"
          >
            Login
          </button>

        </form>

        {/* Register link */}
        <p className="text-center text-sm mt-4">
          Don't have an account?
          <span
            onClick={() => navigate("/register")}
            className="underline cursor-pointer hover:text-white/80 ml-1"
          >
            Register
          </span>
        </p>

      </div>
    </div>
  );
};

export default Login;
